/* =====================================================
   search.js — Secure Fuse.js search for بلتاجي الرمحي
   Security: DOM creation (no innerHTML with raw data)
   ===================================================== */
document.addEventListener('DOMContentLoaded', function () {

    let fuse = null;

    // Fetch JSON index generated by Hugo
    fetch(window.searchIndexUrl)
        .then(res => res.json())
        .then(data => {
            const options = {
                keys: [
                    { name: 'title',   weight: 0.7 },
                    { name: 'summary', weight: 0.2 },
                    { name: 'content', weight: 0.1 }
                ],
                includeScore:     true,
                threshold:        0.4,
                ignoreLocation:   true,
                useExtendedSearch: true
            };
            fuse = new Fuse(data, options);
        })
        .catch(err => console.error('تعذّر تحميل فهرس البحث:', err));

    const searchInput   = document.getElementById('search-input');
    const searchResults = document.getElementById('search-results');

    if (!searchInput || !searchResults) return;

    searchInput.addEventListener('input', function (e) {
        const query = e.target.value.trim();

        searchResults.innerHTML = '';

        if (!query || !fuse) return;

        const results = fuse.search(query);

        if (results.length === 0) {
            const msg = document.createElement('p');
            msg.className = 'text-center py-4 font-ibm';
            msg.style.color = 'var(--ink-500)';
            msg.textContent = 'لا توجد نتائج.';
            searchResults.appendChild(msg);
            return;
        }

        results.forEach(({ item: doc }) => {
            // Choose icon & color per section (safe — no user data in attributes)
            const iconMap  = { poetry: 'feather', quotes: 'quote', thoughts: 'lightbulb' };
            const colorMap = { poetry: 'var(--gold-400)', quotes: 'var(--violet-500)', thoughts: 'var(--teal-400)' };

            const icon  = iconMap[doc.section]  || 'file-text';
            const color = colorMap[doc.section] || 'var(--ink-500)';

            // Build DOM safely — no innerHTML with data
            const anchor = document.createElement('a');
            anchor.href      = doc.permalink;
            anchor.className = 'flex items-start gap-3 p-4 rounded-xl transition-colors hover:no-underline';
            anchor.style.cssText = 'background:transparent;';
            anchor.addEventListener('mouseenter', () => {
                anchor.style.background = 'rgba(212,144,58,0.06)';
            });
            anchor.addEventListener('mouseleave', () => {
                anchor.style.background = 'transparent';
            });

            const iconEl = document.createElement('i');
            iconEl.setAttribute('data-lucide', icon);
            iconEl.className = 'w-5 h-5 mt-0.5 shrink-0';
            iconEl.style.color = color;

            const textWrap = document.createElement('div');
            textWrap.className = 'flex-1 min-w-0';

            const title = document.createElement('h4');
            title.className = 'font-bold font-reem text-base';
            title.style.color = 'var(--ink-900)';
            title.textContent = doc.title;   // textContent — XSS-safe

            const summary = document.createElement('p');
            summary.className = 'text-sm font-ibm truncate mt-0.5';
            summary.style.color = 'var(--ink-500)';
            summary.textContent = doc.summary; // textContent — XSS-safe

            textWrap.appendChild(title);
            textWrap.appendChild(summary);
            anchor.appendChild(iconEl);
            anchor.appendChild(textWrap);
            searchResults.appendChild(anchor);
        });

        // Re-render Lucide icons for newly created elements
        lucide.createIcons();
    });
});
